// src/api/verificationApi.js
import axios from 'axios';
import { Platform } from 'react-native';

const API_BASE_URL = 'https://api.taxidevilleyaounde.com';
// const API_BASE_URL = 'http://localhost:4000'; 


export async function uploadVerificationDocument(verificationId, docType, file) {
  if (!verificationId) throw new Error("verificationId is required");
  if (!docType) throw new Error("docType is required");
  if (!file) throw new Error("file is required");

  const url = `${API_BASE_URL}/api/verification/${verificationId}/document`;

  const formData = new FormData();
  formData.append("docType", docType);

  if (Platform.OS === "web") {
    // ✅ If you already have a real File, use it directly
    if (file?.__webFile instanceof File) {
      formData.append("file", file.__webFile, file.__webFile.name);
    } else if (file instanceof File) {
      formData.append("file", file, file.name);
    } else if (file?.uri) {
      // ✅ Convert uri -> Blob -> File
      const res = await fetch(file.uri);
      const blob = await res.blob();

      const name = file.name || "document";
      const type = file.mimeType || file.type || blob.type || "application/octet-stream";

      const webFile = new File([blob], name, { type });
      formData.append("file", webFile, webFile.name);
    } else {
      throw new Error("Web upload: file must be a File or an object with { uri }");
    }

    // ✅ IMPORTANT: DO NOT set Content-Type on web (boundary must be auto-set)
    const response = await axios.post(url, formData);
    return response.data;
  }

  // ✅ Native (Android/iOS)
  if (!file?.uri) {
    throw new Error("Native upload: file.uri is required");
  }

  formData.append("file", {
    uri: file.uri,
    name: file.name || "document",
    type: file.mimeType || file.type || "application/octet-stream",
  });

  const response = await axios.post(url, formData, {
    headers: {
      // ✅ On native, this is okay
      "Content-Type": "multipart/form-data",
    },
  });

  return response.data;
}




export async function completeVerification(verificationId) {
  if (!verificationId) {
    throw new Error('verificationId manquant.');
  }
  const res = await axios.post(
    `${API_BASE_URL}/api/verification/${verificationId}/complete`
  );
  return res.data;
}
